import { useState,useEffect } from "react";
import {Link} from 'react-router-dom';
import axios from 'axios';
export default function Utilisateur(){
    const [users,setUsers] = useState([]);
    const token = localStorage.getItem("token");
    const [search,setSearch] = useState('');
    const getUsers = async () => {
        const res = await axios.get('http://localhost:3001/users', {
          headers: { Authorization: `Bearer ${token}`}
        });
        setUsers(res.data);
    }
    useEffect(() => {
        getUsers();
    },[]);
    return (
        <>
            <Link to='/AjouterUtilisateur'>Ajouter un utilisateur</Link>
                <input type="text" value={search} onChange={(e) => setSearch(e.target.value)}/>
                <button onClick={async() => {
                    await axios.get
                }}></button>
            <center>
                <table border='1'>
                <tr>
                    <th>name</th>
                    <th>email</th>
                    <th>role</th>
                    <th>actions</th>
                </tr>
                {users.map((u,i) => (
                    <tr key={i}>
                        <td>{u.username}</td>
                        <td>{u.email}</td>
                        <td>{u.role}</td>
                        <td>
                            <button onClick={ async () => {
                                await axios.delete(`http://localhost:3001/delete/${u._id}`,{
                                headers: { Authorization: `Bearer ${token}` }
                                })
                                setUsers(prev => prev.filter(user => user._id !== u._id));
                            }}>supprimer</button>
                            <Link to={`/modifierUtilisateur/${u._id}`}>modifier</Link>             
                            </td>
                        {/* <td><Link to={`/details/${u._id}`}>details</Link></td> */}
                    </tr>
                ))}
                 </table>
            </center>
           

        </>
    )
    
}
